            absA := a
            if absA < 0 {
                absA = -absA
            }
            absB := b
            if absB < 0 {
                absB = -absB
            }
            minAB := absA
            maxAB := absB
            if absA > absB {
                minAB = absB
                maxAB = absA
            }

            diff := a - b
            if diff < 0 {
                diff = -diff
            }
            sum := a + b
            if sum < 0 {
                sum = -sum
            }

            minDiffSum := diff
            if sum < diff {
                minDiffSum = sum
            }
            maxDiffSum := diff
